noncompliant:
// Using # (stringification) operator
#define STRINGIFY(x) #x     // Noncompliant: # operator
#define DEBUG_PRINT(var) printf(#var " = %d\n", var)  // Noncompliant

void example_usage() {
    int count = 10;
    DEBUG_PRINT(count);  // Expands to: printf("count" " = %d\n", count);
}

// Using ## (token concatenation) operator
#define CONCAT(a, b) a##b   // Noncompliant: ## operator
#define MAKE_FUNCTION(name) void func_##name() { /* ... */ }  // Noncompliant

// Usage
MAKE_FUNCTION(init)     // Creates: void func_init() { /* ... */ }
MAKE_FUNCTION(cleanup)  // Creates: void func_cleanup() { /* ... */ }

// Complex macro using both operators
#define LOG_FUNCTION(level, name) \
    void log_##level##_##name() { \
        printf("Function: " #name " at level " #level "\n"); \
    }  // Noncompliant: uses both # and ##

LOG_FUNCTION(error, database)  // Creates complex function name

compliant:
// Alternative to stringification: explicit strings
#define DEBUG_PRINT(var, name) printf(name " = %d\n", var)  // Compliant

void example_usage() {
    int count = 10;
    DEBUG_PRINT(count, "count");  // Explicit string instead of #
}

// Simple macro without operators
#define MAX_SIZE 1024       // Compliant: simple definition

// Alternative to token concatenation: separate functions
// Instead of generating functions with ##, define them explicitly
void func_init() {      // Compliant: explicit function
    // initialization code
}

void func_cleanup() {   // Compliant: explicit function
    // cleanup code
}

// Use function pointers for dynamic selection
typedef void (*func_ptr)();
func_ptr get_function(const char* name) {
    if (strcmp(name, "init") == 0) return func_init;
    if (strcmp(name, "cleanup") == 0) return func_cleanup;
    return NULL;
}

// Using const variables instead of complex macros
const char* const LOG_LEVELS[] = {"debug", "info", "error"};  // Compliant

void log_message(int level, const char* function_name, const char* message) {
    printf("[%s] %s: %s\n", LOG_LEVELS[level], function_name, message);
}

// Usage
void database_function() {
    log_message(2, "database_function", "Error occurred");  // Compliant
}
